#ifndef GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_
#define GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>
#include <torch/extension.h>

// Fixed constants from spec
static constexpr int kNumQoHeads = 32;
static constexpr int kNumKvHeads = 8;
static constexpr int kHeadDim = 128;
static constexpr int kGqaRatio = kNumQoHeads / kNumKvHeads;  // 4

void LaunchGqaRaggedPrefillCausalH32Kv8D128(
    const at::BFloat16* q,     // [total_q, 32, 128]
    const at::BFloat16* k,     // [total_kv, 8, 128]
    const at::BFloat16* v,     // [total_kv, 8, 128]
    const int32_t* qo_indptr,  // [B+1] on CUDA
    const int32_t* kv_indptr,  // [B+1] on CUDA
    int32_t len_indptr,        // B+1
    int32_t total_q,
    float sm_scale,
    at::BFloat16* output,      // [total_q, 32, 128]
    float* lse,                // [total_q, 32] log2sumexp
    cudaStream_t stream);

#endif  // GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>

#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
#include <cuda_bf16.h>
#endif

#ifndef CUDART_INF_F
#define CUDART_INF_F __int_as_float(0x7f800000)
#endif

static constexpr uint32_t kFullMask = 0xffffffffu;

static __device__ __forceinline__ float bf16_to_f32(at::BFloat16 x) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
  __nv_bfloat16 bx = *reinterpret_cast<const __nv_bfloat16*>(&x);
  return __bfloat162float(bx);
#else
  union {
    uint32_t u32;
    float f;
  } u;
  uint16_t u16 = *reinterpret_cast<const uint16_t*>(&x);
  u.u32 = (uint32_t)u16 << 16;
  return u.f;
#endif
}

static __device__ __forceinline__ at::BFloat16 f32_to_bf16_rn(float x) {
#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
  __nv_bfloat16 b = __float2bfloat16_rn(x);
  return *reinterpret_cast<at::BFloat16*>(&b);
#else
  union {
    uint32_t u32;
    float f;
  } u;
  u.f = x;
  uint16_t u16 = (uint16_t)(u.u32 >> 16);
  return *reinterpret_cast<at::BFloat16*>(&u16);
#endif
}

static __device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
  for (int off = 16; off > 0; off >>= 1) v += __shfl_down_sync(kFullMask, v, off);
  return v;
}
static __device__ __forceinline__ float warp_reduce_max(float v) {
#pragma unroll
  for (int off = 16; off > 0; off >>= 1) v = fmaxf(v, __shfl_down_sync(kFullMask, v, off));
  return v;
}

// Block reductions for blockDim.x == 256 (8 warps)
static __device__ __forceinline__ float block_reduce_sum_256(float v) {
  __shared__ float sm[8];
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;
  float w = warp_reduce_sum(v);
  if (lane == 0) sm[warp] = w;
  __syncthreads();
  float out = 0.f;
  if (warp == 0) {
    out = (lane < 8) ? sm[lane] : 0.f;
    out = warp_reduce_sum(out);
  }
  return __shfl_sync(kFullMask, out, 0);
}

static __device__ __forceinline__ float block_reduce_max_256(float v) {
  __shared__ float sm[8];
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;
  float w = warp_reduce_max(v);
  if (lane == 0) sm[warp] = w;
  __syncthreads();
  float out = -CUDART_INF_F;
  if (warp == 0) {
    out = (lane < 8) ? sm[lane] : -CUDART_INF_F;
    out = warp_reduce_max(out);
  }
  return __shfl_sync(kFullMask, out, 0);
}

// Find batch for q_idx by binary search on qo_indptr.
static __device__ __forceinline__ int32_t find_batch_for_q_device(
    const int32_t* __restrict__ qo_indptr, int32_t len_indptr, int32_t q_idx) {
  int32_t lo = 0;
  int32_t hi = len_indptr - 2;
  while (lo <= hi) {
    int32_t mid = (lo + hi) >> 1;
    int32_t s = __ldg(qo_indptr + mid);
    int32_t e = __ldg(qo_indptr + mid + 1);
    if (q_idx < s) {
      hi = mid - 1;
    } else if (q_idx >= e) {
      lo = mid + 1;
    } else {
      return mid;
    }
  }
  return -1;
}

__global__ __launch_bounds__(256, 2) void gqa_ragged_prefill_causal_h32_kv8_d128_kernel(
    const at::BFloat16* __restrict__ q,
    const at::BFloat16* __restrict__ k,
    const at::BFloat16* __restrict__ v,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    at::BFloat16* __restrict__ out,
    float* __restrict__ lse_out) {
  int64_t linear = (int64_t)blockIdx.x;
  int32_t q_idx = (int32_t)(linear / kNumQoHeads);
  int32_t hq = (int32_t)(linear - (int64_t)q_idx * kNumQoHeads);
  if (q_idx >= total_q) return;

  int32_t b = find_batch_for_q_device(qo_indptr, len_indptr, q_idx);
  if (b < 0) return;

  int32_t q_start = __ldg(qo_indptr + b);
  int32_t q_end = __ldg(qo_indptr + b + 1);
  int32_t kv_start = __ldg(kv_indptr + b);
  int32_t kv_end = __ldg(kv_indptr + b + 1);
  if (q_start >= q_end || kv_start >= kv_end) return;

  int32_t num_q = q_end - q_start;
  int32_t num_kv = kv_end - kv_start;
  int32_t delta = num_kv - num_q;

  int32_t q_local = q_idx - q_start;

  // Mask rule: kv_pos < q_pos + 1 + delta
  int32_t max_kv_allowed = q_local + 1 + delta;  // exclusive
  if (max_kv_allowed < 0) max_kv_allowed = 0;
  if (max_kv_allowed > num_kv) max_kv_allowed = num_kv;
  if (max_kv_allowed == 0) return;

  int32_t hk = hq / kGqaRatio;  // 0..7

  const at::BFloat16* q_ptr = q + ((int64_t)q_idx * kNumQoHeads + hq) * kHeadDim;
  const int64_t kv_head_offset = (int64_t)hk * kHeadDim;

  // Pass1: max(logits)
  float tmax = -CUDART_INF_F;
  for (int32_t j = threadIdx.x; j < max_kv_allowed; j += 256) {
    const at::BFloat16* k_ptr =
        k + ((int64_t)(kv_start + j) * (kNumKvHeads * kHeadDim) + kv_head_offset);

    float acc = 0.f;
#pragma unroll
    for (int d = 0; d < kHeadDim; ++d) {
      acc = fmaf(bf16_to_f32(q_ptr[d]), bf16_to_f32(k_ptr[d]), acc);
    }
    tmax = fmaxf(tmax, acc * sm_scale);
  }
  float m = block_reduce_max_256(tmax);

  // Pass2: sum(exp(logits - m))
  float tsum = 0.f;
  for (int32_t j = threadIdx.x; j < max_kv_allowed; j += 256) {
    const at::BFloat16* k_ptr =
        k + ((int64_t)(kv_start + j) * (kNumKvHeads * kHeadDim) + kv_head_offset);

    float acc = 0.f;
#pragma unroll
    for (int d = 0; d < kHeadDim; ++d) {
      acc = fmaf(bf16_to_f32(q_ptr[d]), bf16_to_f32(k_ptr[d]), acc);
    }
    tsum += __expf(acc * sm_scale - m);
  }
  float s = block_reduce_sum_256(tsum);

  // Write lse in log2 domain.
  if (threadIdx.x == 0) {
    float lse_log2 = (m + logf(s)) * 1.4426950408889634f;  // 1/ln(2)
    lse_out[(int64_t)q_idx * kNumQoHeads + hq] = lse_log2;
  }

  // Pass3: output = sum_j softmax_j * v_j
  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  float acc0 = 0.f, acc1 = 0.f, acc2 = 0.f, acc3 = 0.f;
  for (int32_t j = threadIdx.x; j < max_kv_allowed; j += 256) {
    const at::BFloat16* k_ptr =
        k + ((int64_t)(kv_start + j) * (kNumKvHeads * kHeadDim) + kv_head_offset);
    const at::BFloat16* v_ptr =
        v + ((int64_t)(kv_start + j) * (kNumKvHeads * kHeadDim) + kv_head_offset);

    float dot = 0.f;
#pragma unroll
    for (int d = 0; d < kHeadDim; ++d) {
      dot = fmaf(bf16_to_f32(q_ptr[d]), bf16_to_f32(k_ptr[d]), dot);
    }
    float w = __expf(dot * sm_scale - m) / s;

    int d0 = lane;
    acc0 = fmaf(w, bf16_to_f32(v_ptr[d0]), acc0);
    acc1 = fmaf(w, bf16_to_f32(v_ptr[d0 + 32]), acc1);
    acc2 = fmaf(w, bf16_to_f32(v_ptr[d0 + 64]), acc2);
    acc3 = fmaf(w, bf16_to_f32(v_ptr[d0 + 96]), acc3);
  }

  __shared__ float warp_part[8][32][4];
  warp_part[warp][lane][0] = acc0;
  warp_part[warp][lane][1] = acc1;
  warp_part[warp][lane][2] = acc2;
  warp_part[warp][lane][3] = acc3;
  __syncthreads();

  if (warp == 0) {
    float r0 = 0.f, r1 = 0.f, r2 = 0.f, r3 = 0.f;
#pragma unroll
    for (int w = 0; w < 8; ++w) {
      r0 += warp_part[w][lane][0];
      r1 += warp_part[w][lane][1];
      r2 += warp_part[w][lane][2];
      r3 += warp_part[w][lane][3];
    }
    at::BFloat16* o_ptr = out + ((int64_t)q_idx * kNumQoHeads + hq) * kHeadDim;
    o_ptr[lane] = f32_to_bf16_rn(r0);
    o_ptr[lane + 32] = f32_to_bf16_rn(r1);
    o_ptr[lane + 64] = f32_to_bf16_rn(r2);
    o_ptr[lane + 96] = f32_to_bf16_rn(r3);
  }
}

void LaunchGqaRaggedPrefillCausalH32Kv8D128(
    const at::BFloat16* q,
    const at::BFloat16* k,
    const at::BFloat16* v,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    at::BFloat16* output,
    float* lse,
    cudaStream_t stream) {
  constexpr int threads = 256;
  int64_t blocks64 = (int64_t)total_q * (int64_t)kNumQoHeads;
  if (blocks64 <= 0) return;

  // grid.x is uint32
  if (blocks64 > (int64_t)0xFFFFFFFFu) blocks64 = (int64_t)0xFFFFFFFFu;

  dim3 grid((uint32_t)blocks64, 1, 1);
  dim3 block(threads, 1, 1);

  gqa_ragged_prefill_causal_h32_kv8_d128_kernel<<<grid, block, 0, stream>>>(
      q, k, v, qo_indptr, kv_indptr, len_indptr, total_q, sm_scale, output, lse);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <vector>
#include <cmath>
#include <limits>

#include "kernel.h"

#define CHECK_CUDA(x) TORCH_CHECK((x).device().is_cuda(), #x " must be a CUDA tensor")
#define CHECK_CONTIG(x) TORCH_CHECK((x).is_contiguous(), #x " must be contiguous")
#define CHECK_DTYPE(x, dt) TORCH_CHECK((x).dtype() == (dt), #x " must have dtype " #dt)

static void check_shapes(
    const torch::Tensor& q,
    const torch::Tensor& k,
    const torch::Tensor& v,
    const torch::Tensor& qo_indptr,
    const torch::Tensor& kv_indptr) {
  TORCH_CHECK(q.dim() == 3, "q must be [total_q, 32, 128]");
  TORCH_CHECK(k.dim() == 3, "k must be [total_kv, 8, 128]");
  TORCH_CHECK(v.dim() == 3, "v must be [total_kv, 8, 128]");

  TORCH_CHECK(q.size(1) == kNumQoHeads, "q.size(1) must be 32");
  TORCH_CHECK(q.size(2) == kHeadDim, "q.size(2) must be 128");
  TORCH_CHECK(k.size(1) == kNumKvHeads, "k.size(1) must be 8");
  TORCH_CHECK(k.size(2) == kHeadDim, "k.size(2) must be 128");
  TORCH_CHECK(v.sizes() == k.sizes(), "v must have same shape as k");

  TORCH_CHECK(qo_indptr.dim() == 1 && kv_indptr.dim() == 1, "indptr must be 1D");
  TORCH_CHECK(qo_indptr.numel() == kv_indptr.numel(),
              "qo_indptr and kv_indptr must have same length");
  TORCH_CHECK(qo_indptr.numel() >= 2, "indptr length must be >= 2");
}

static void cuda_check_last(const char* msg) {
  cudaError_t err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, msg, ": CUDA error: ", cudaGetErrorString(err));
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    c10::optional<double> sm_scale_opt = c10::nullopt) {
  CHECK_CUDA(q);
  CHECK_CUDA(k);
  CHECK_CUDA(v);
  CHECK_CONTIG(q);
  CHECK_CONTIG(k);
  CHECK_CONTIG(v);
  CHECK_DTYPE(q, torch::kBFloat16);
  CHECK_DTYPE(k, torch::kBFloat16);
  CHECK_DTYPE(v, torch::kBFloat16);

  TORCH_CHECK(qo_indptr.dtype() == torch::kInt32, "qo_indptr must be int32");
  TORCH_CHECK(kv_indptr.dtype() == torch::kInt32, "kv_indptr must be int32");
  TORCH_CHECK(qo_indptr.is_contiguous(), "qo_indptr must be contiguous");
  TORCH_CHECK(kv_indptr.is_contiguous(), "kv_indptr must be contiguous");

  check_shapes(q, k, v, qo_indptr, kv_indptr);

  // Ensure indptr are on CUDA (same device as q)
  torch::Tensor qo_cuda = qo_indptr.device().is_cuda() ? qo_indptr : qo_indptr.to(q.device());
  torch::Tensor kv_cuda = kv_indptr.device().is_cuda() ? kv_indptr : kv_indptr.to(q.device());
  qo_cuda = qo_cuda.contiguous();
  kv_cuda = kv_cuda.contiguous();

  // Validate constraints on CPU (avoid device-side UB from invalid indptr).
  torch::Tensor qo_cpu = qo_indptr.device().is_cuda() ? qo_indptr.to(torch::kCPU) : qo_indptr;
  torch::Tensor kv_cpu = kv_indptr.device().is_cuda() ? kv_indptr.to(torch::kCPU) : kv_indptr;
  qo_cpu = qo_cpu.contiguous();
  kv_cpu = kv_cpu.contiguous();

  int32_t total_q = (int32_t)q.size(0);
  int32_t total_kv = (int32_t)k.size(0);
  int32_t len_indptr = (int32_t)qo_cpu.numel();

  int64_t qo_last = qo_cpu[len_indptr - 1].item<int64_t>();
  int64_t kv_last = kv_cpu[len_indptr - 1].item<int64_t>();
  TORCH_CHECK(qo_last == (int64_t)total_q, "Constraint failed: total_q must equal qo_indptr[-1]");
  TORCH_CHECK(kv_last == (int64_t)total_kv, "Constraint failed: total_kv must equal kv_indptr[-1]");

  float sm_scale = sm_scale_opt.has_value()
                       ? (float)sm_scale_opt.value()
                       : (float)(1.0 / std::sqrt((double)kHeadDim));

  auto out_opts = torch::TensorOptions().device(q.device()).dtype(torch::kBFloat16);
  auto lse_opts = torch::TensorOptions().device(q.device()).dtype(torch::kFloat32);

  torch::Tensor out = torch::zeros({total_q, kNumQoHeads, kHeadDim}, out_opts);
  torch::Tensor lse =
      torch::full({total_q, kNumQoHeads}, -std::numeric_limits<float>::infinity(), lse_opts);

  const at::BFloat16* q_ptr = q.data_ptr<at::BFloat16>();
  const at::BFloat16* k_ptr = k.data_ptr<at::BFloat16>();
  const at::BFloat16* v_ptr = v.data_ptr<at::BFloat16>();
  const int32_t* qo_ptr = qo_cuda.data_ptr<int32_t>();
  const int32_t* kv_ptr = kv_cuda.data_ptr<int32_t>();
  at::BFloat16* out_ptr = out.data_ptr<at::BFloat16>();
  float* lse_ptr = lse.data_ptr<float>();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  LaunchGqaRaggedPrefillCausalH32Kv8D128(
      q_ptr, k_ptr, v_ptr, qo_ptr, kv_ptr, len_indptr, total_q, sm_scale, out_ptr, lse_ptr, stream);

  cuda_check_last("gqa_ragged_prefill_causal_h32_kv8_d128 launch failed");

  cudaError_t sync_err = cudaStreamSynchronize(stream);
  TORCH_CHECK(sync_err == cudaSuccess, "CUDA stream sync failed: ", cudaGetErrorString(sync_err));

  return {out, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run",
        &run,
        "Kernel execution function (gqa_ragged_prefill_causal_h32_kv8_d128 CUDA)",
        py::arg("q"),
        py::arg("k"),
        py::arg("v"),
        py::arg("qo_indptr"),
        py::arg("kv_indptr"),
        py::arg("sm_scale") = py::none());
}
